// Build Rank Prompt â€” Agent 10 (Job Ranker) â€” BATCHED
// Emits ONE ITEM PER CHUNK so the downstream Split In Batches loop sends each
// chunk to Call LLM separately. The single-call version truncated at the model's
// 8192-output-token ceiling once job count pushed the JSON array past ~266 jobs
// (â‰ˆ30 output tokens/job). Chunking keeps every call's output well under the cap.
//
// CRITICAL: jobs are numbered with their GLOBAL index (1-based across the whole
// run, not per-chunk), so the LLM's "i" values are unique across batches and
// Apply Rank can merge all batches by "i" without collision.
$getWorkflowStaticData('global').rankerBatches = [];
const trigger = $input.first().json;
const config = trigger.config || {};
const jobs = Array.isArray(trigger.jobs) ? trigger.jobs : [];

const strip = (v) => {
  if (v === null || v === undefined) return '';
  if (typeof v !== 'string') return v;
  let cleaned = v;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') cleaned = cleaned.substring(1);
  return cleaned;
};
const systemPrompt = strip(trigger.system_prompt);
const target_titles = strip(config.target_titles);
const background_titles = strip(config.background_titles);
const target_locations = strip(config.target_location) || strip(config.applicant_location);
const target_country = strip(config.target_country);

const OUTPUT_CONTRACT = `
## OUTPUT FORMAT
Output STRICT JSON only. No prose. No markdown fences. Format: a JSON array of objects { "i": <the exact index number shown for each job below>, "t": <target_title_relevance int 0-100>, "b": <background_title_relevance int 0-100>, "l": <location_fit int 0-100> }. Use the SAME index number shown next to each job (do not renumber from 1). Include every job in this batch exactly once. Order does not matter. If background_titles is blank, return "b": 0 for every job.`;
const system = systemPrompt + OUTPUT_CONTRACT;

// Chunk size: 150 jobs * ~30 output tokens = ~4500 tokens, safely under the
// 8192 model output ceiling. Tunable via config.discovery_rank_chunk_size.
const cfgChunk = parseInt(config.discovery_rank_chunk_size, 10);
const CHUNK = Number.isFinite(cfgChunk) && cfgChunk > 0 ? cfgChunk : 150;

const cfgFloor = parseInt(config.max_tokens_discovery_ranker, 10);
const floor = Number.isFinite(cfgFloor) && cfgFloor > 0 ? cfgFloor : 2000;

const fmtLoc = (j) => {
  const rawLoc = j.location || '';
  return rawLoc ? (j.remote ? `${rawLoc} (remote)` : rawLoc) : (j.remote ? 'Remote' : 'Unknown');
};

const items = [];
const totalChunks = Math.max(1, Math.ceil(jobs.length / CHUNK));
for (let c = 0; c < totalChunks; c++) {
  const start = c * CHUNK;
  const slice = jobs.slice(start, start + CHUNK);
  // Number with GLOBAL index (start + i + 1) so "i" is unique across batches.
  const jobLines = slice.map((j, i) => {
    const globalIdx = start + i + 1;
    return `${globalIdx}. title="${j.title || 'Unknown'}" | company="${j.company || 'Unknown'}" | location="${fmtLoc(j)}"`;
  }).join('\n');

  const user_message = `Target titles: ${target_titles}
Background titles: ${background_titles || '(none â€” score "b" as 0 for every job)'}
Target locations: ${target_locations}
Target country: ${target_country || '(any)'}
Jobs (batch ${c + 1} of ${totalChunks}, ${slice.length} jobs; use the index number shown for each):
${jobLines}
Return the JSON array now.`;

  // Per-chunk max_tokens sized to this chunk only.
  const chunkMaxTokens = Math.min(8000, Math.max(floor, slice.length * 30));

  items.push({
    json: {
      ...trigger,
      system,
      user_message,
      max_tokens: chunkMaxTokens,
      _batch_index: c + 1,
      _batch_total: totalChunks,
      _batch_size: slice.length
    }
  });
}

console.log(`[Build Rank Prompt] ${jobs.length} jobs -> ${items.length} batch(es) of <=${CHUNK}; system: ${system.length} chars`);
return items;

// Apply Rank â€” Agent 10 (Job Ranker) â€” BATCHED
// Reads accumulated batch outputs from static data (Collect Batch pushed each
// loop iteration). Merges scores by the GLOBAL "i" the prompt numbered each job
// with. Emits one item per ranked job plus one usage item. Cap applied downstream.

const trigger = $('Trigger').first().json;
const jobs = Array.isArray(trigger.jobs) ? trigger.jobs : [];
const config = trigger.config || {};
const watchlist = Array.isArray(trigger.watchlist) ? trigger.watchlist : [];
const runId = trigger.run_id || '';

const wt = Number(config.discovery_rank_weight_title ?? 0.75);
const wl = Number(config.discovery_rank_weight_location ?? 0.25);
const watchlistBoost = Number(config.discovery_rank_watchlist_boost ?? 10);
const floor = Number(config.discovery_rank_floor ?? 30);
const locationHardFloor = Number(config.discovery_rank_location_hard_floor ?? 20);
const titleHardFloor = Number(config.discovery_rank_title_hard_floor ?? 25);

const normCompany = (s) => {
  let v = String(s || '').toLowerCase().replace(/[.,]/g, ' ').replace(/\s+/g, ' ').trim();
  v = v.replace(/^the\s+/, '');
  for (let i = 0; i < 3; i++) {
    const next = v.replace(/\s+(inc|llc|corp|corporation|ltd|limited|co|company|gmbh|sa|ag|plc|nv|bv|pty|holdings|group)$/, '').trim();
    if (next === v) break;
    v = next;
  }
  return v;
};
const watchlistSet = new Set(
  watchlist.map(w => normCompany(typeof w === 'string' ? w : (w?.company ?? w?.name ?? '')))
);

// --- Parse LLM scores across ALL batches (from static data) ---
const staticData = $getWorkflowStaticData('global');
const llmItems = (staticData.rankerBatches || []).map(j => ({ json: j }));
staticData.rankerBatches = []; // reset for next run

let scores = [];
let anyBatchFailed = false;
let anyParseFailed = false;
let failReason = '';
let aggIn = 0, aggOut = 0, aggCacheRead = 0, aggCacheWrite = 0;
let modelUsed = '';
let providerUsed = config.provider_discovery_ranker || 'anthropic';

for (const item of llmItems) {
  const out = item.json || {};
  if (out.success === false) {
    anyBatchFailed = true;
    failReason = out?.error?.message || out?.errors?.[0] || 'LLM call failed';
    continue;
  }
  try {
    const raw = out?.message?.content?.[0]?.text
      ?? out?.message?.content
      ?? out?.content?.[0]?.text
      ?? out?.content
      ?? out?.output
      ?? '';
    const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
    const match = text.match(/\[[\s\S]*\]/);
    if (match) {
      const arr = JSON.parse(match[0]);
      if (Array.isArray(arr)) scores = scores.concat(arr);
      else anyParseFailed = true;
    } else {
      anyParseFailed = true;
    }
  } catch (e) {
    console.log('[Apply Rank] batch parse failed:', e.message);
    anyParseFailed = true;
  }
  const u = out?.usage || out?.message?.usage || {};
  aggIn         += Number(out.input_tokens ?? u.input_tokens ?? u.prompt_tokens ?? 0);
  aggOut        += Number(out.output_tokens ?? u.output_tokens ?? u.completion_tokens ?? 0);
  aggCacheRead  += Number(out.cached_input_tokens ?? u.cache_read_input_tokens ?? 0);
  aggCacheWrite += Number(out.cache_write_tokens ?? u.cache_creation_input_tokens ?? 0);
  if (!modelUsed) modelUsed = out?.model_used ?? out?.model ?? out?.message?.model ?? '';
}

// --- Hard-fail on incomplete ranking ---
const noScores = !Array.isArray(scores) || scores.length === 0;
if (anyBatchFailed || anyParseFailed || noScores) {
  const reason = anyBatchFailed
    ? failReason
    : (anyParseFailed ? 'one or more batches could not be parsed (possible truncation)' : 'no scores returned');
  throw new Error(`[Apply Rank] Ranker produced incomplete scores across ${llmItems.length} batch(es) â€” failing run rather than ranking on partial data. Reason: ${reason}`);
}

const scoreByIdx = new Map();
for (const s of scores) {
  if (typeof s?.i === 'number') {
    scoreByIdx.set(s.i, { t: Number(s.t ?? 0), b: Number(s.b ?? 0), l: Number(s.l ?? 0) });
  }
}

const annotated = jobs.map((job, idx) => {
  const s = scoreByIdx.get(idx + 1);
  const missing = !s;
  const titleTarget = s ? s.t : 50;
  const titleBackground = s ? s.b : 50;
  const locationFit = s ? s.l : 50;
  const titleBest = Math.max(titleTarget, titleBackground);
  const inWatchlist = watchlistSet.has(normCompany(job.company));
  const weighted = (wt * titleBest) + (wl * locationFit);
  const rankScore = weighted + (inWatchlist ? watchlistBoost : 0);
  const failsLocation = !missing && locationFit < locationHardFloor;
  const failsTitle = !missing && titleTarget < titleHardFloor && titleBackground < titleHardFloor;
  return {
    ...job,
    _title_relevance_target: titleTarget,
    _title_relevance_background: titleBackground,
    _title_relevance_best: titleBest,
    _location_fit: locationFit,
    _in_watchlist: inWatchlist,
    _rank_score: rankScore,
    _ranker_fallback: missing,
    _location_gate_failed: failsLocation,
    _title_gate_failed: failsTitle,
  };
});

const droppedByLocation = annotated.filter(j => j._location_gate_failed).length;
const droppedByTitle = annotated.filter(j => j._title_gate_failed && !j._location_gate_failed).length;

const ranked = annotated
  .filter(j => !j._location_gate_failed)
  .filter(j => !j._title_gate_failed)
  .filter(j => j._rank_score >= floor)
  .sort((a, b) => b._rank_score - a._rank_score);

console.log(`[Apply Rank] ${jobs.length} input across ${llmItems.length} batch(es), ${scores.length} scores, dropped ${droppedByLocation} by location, ${droppedByTitle} by title, ${ranked.length} above floor (${floor})`);

const PRICING = {
  'claude-haiku-4-5-20251001': { i: 1.00, o: 5.00, cr: 0.10, cw: 1.25 },
  'claude-haiku-4-5':          { i: 1.00, o: 5.00, cr: 0.10, cw: 1.25 },
  'claude-sonnet-4-5-20250929':{ i: 3.00, o: 15.00, cr: 0.30, cw: 3.75 },
  'claude-sonnet-4-6':         { i: 3.00, o: 15.00, cr: 0.30, cw: 3.75 },
  'claude-opus-4-6':           { i: 15.00, o: 75.00, cr: 1.50, cw: 18.75 },
  'claude-opus-4-7':           { i: 15.00, o: 75.00, cr: 1.50, cw: 18.75 },
};
const rate = PRICING[modelUsed] || PRICING['claude-haiku-4-5-20251001'];
const cost = ((aggIn * rate.i) + (aggOut * rate.o) + (aggCacheRead * rate.cr) + (aggCacheWrite * rate.cw)) / 1_000_000;

const usage = {
  _type: 'usage',
  run_id: runId,
  agent_id: 'agent_10',
  tokens: { input: aggIn, output: aggOut },
  cached_input_tokens: aggCacheRead,
  cache_write_tokens: aggCacheWrite,
  cost,
  model_used: modelUsed,
  provider_used: providerUsed,
  scored_at: new Date().toISOString(),
};

const out = ranked.map(j => ({ json: j }));
out.push({ json: usage });
return out;

// Summarize â€” Agent 10 (Job Ranker)
// Collapses Apply Rank's per-job emit stream into one item with usage.
// Reads Call LLM's normalized response (top-level input_tokens etc.) and
// computes cost using Trigger.pricing. Filters out the {_type:'usage'} sentinel
// that Apply Rank pushes so the jobs array contains only real jobs.

const items = $input.all().map(i => i.json);
const jobs = items.filter(j => j && j._type !== 'usage' && (j.url || j.title));

const llmOut = $('Call LLM').first()?.json || {};
const triggerData = $('Trigger').first().json;
const config = triggerData.config || {};

// Pricing may arrive as a JSON string if the parent's Execute Workflow node has
// convertFieldsToString:true. Parse defensively.
let pricing = triggerData.pricing || {};
if (typeof pricing === 'string') {
  try { pricing = JSON.parse(pricing); } catch (e) { pricing = {}; }
}

const modelUsed    = llmOut.model_used    || config.model_discovery_ranker    || 'unknown';
const providerUsed = llmOut.provider_used || config.provider_discovery_ranker || 'unknown';
const tokensInput  = Number(llmOut.input_tokens         || 0);
const tokensOutput = Number(llmOut.output_tokens        || 0);
const cachedInput  = Number(llmOut.cached_input_tokens  || 0);
const cacheWrite   = Number(llmOut.cache_write_tokens   || 0);

const rates = pricing[modelUsed] || null;
const cost = rates ? (
  tokensInput  / 1e6 * (rates.input_per_million        || 0) +
  tokensOutput / 1e6 * (rates.output_per_million       || 0) +
  cachedInput  / 1e6 * (rates.cached_input_per_million || 0) +
  cacheWrite   / 1e6 * (rates.cache_write_per_million  || 0)
) : 0;

if (!rates) {
  console.log(`[Summarize] WARNING: no pricing for model "${modelUsed}". Cost will be 0. Pricing keys available: ${Object.keys(pricing).join(', ') || '(none)'}`);
}

const usage = {
  model_used: modelUsed,
  provider_used: providerUsed,
  tokens: { input: tokensInput, output: tokensOutput },
  cached_input_tokens: cachedInput,
  cache_write_tokens: cacheWrite,
  cost
};

console.log(`[Job Post Processing] ${jobs.length} jobs after dedup/limit; agent_10 usage: ${tokensInput}in/${tokensOutput}out, cost=$${cost.toFixed(6)}, model=${modelUsed}`);

return [{ json: { jobs, count: jobs.length, usage } }];

// Set Inputs â€” Agent 10: Job Ranker
// Reads ranker-specific config keys, validates them, and emits a flat payload
// for Build Rank Prompt + Call LLM. Mirrors Agent 8's Set Inputs pattern so
// the ranker has its own dedicated model/provider/max_tokens config, fully
// independent from the scorer.
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt || trigger.pre_ranker_prompt);

const provider = strip(config.provider_discovery_ranker);
if (!provider) throw new Error('[Agent 10] config.provider_discovery_ranker is required.');
const model = strip(config.model_discovery_ranker);
if (!model) throw new Error('[Agent 10] config.model_discovery_ranker is required.');

// max_tokens floor is read by Build Rank Prompt from config.max_tokens_discovery_ranker
// (dynamic per job count). Don't validate it here â€” Build Rank Prompt has a 2000 fallback.

console.log(`[Agent 10 Set Inputs] jobs=${(trigger.jobs || []).length}, provider=${provider}, model=${model}`);

console.log(`[Agent 10 Set Inputs] jobs=${(trigger.jobs || []).length}, provider=${provider}, model=${model}`);

// Do NOT spread the fat jobs array forward. Build Rank Prompt only needs slim
// job fields to build the LLM prompt; Apply Rank reads the FULL jobs from
// $('Trigger') directly (so description_html etc. survive for the recorder).
// Forwarding 39MB through here + Build Rank Prompt + Call LLM is what times out
// the task runner on serialization. Pass slim jobs for the prompt only.
const slimJobs = (Array.isArray(trigger.jobs) ? trigger.jobs : []).map(j => ({
  title: j.title,
  company: j.company,
  location: j.location,
  remote: j.remote
}));
const { jobs: _fat, ...triggerRest } = trigger;

return {
  json: {
    ...triggerRest,
    jobs: slimJobs,
    config,
    system_prompt: systemPrompt,
    provider,
    model
  }
};

// Collect Batch â€” persist each loop iteration's Call LLM output so Apply Rank
// can read ALL batches. ($('Call LLM').all() only returns the last iteration.)
const staticData = $getWorkflowStaticData('global');
if (!staticData.rankerBatches) staticData.rankerBatches = [];
staticData.rankerBatches.push($input.first().json);
return $input.all();
